{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00から1時間で開催し、リモート参加可・各部署から1名参加の運用とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行はマスタ系を先行し、トランザクション系は第1フェーズでは扱わず旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信基盤はサクラ商事さんとの共同利用案（第3案）で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "移行方式は拠点をグループ分けして順番に切り替える段階移行を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリース目標を2026-10-15に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "新システムのユーザー権限は既存のロール定義を流用し、新規設計はしない。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "障害の一次受け窓口はQAチームとし、切り分け後に必要なものだけ情シスへエスカレーションする。",
      "decided_by": "桐生 遥"
    }
  ],
